fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let mut nums = nums;
    nums.sort();
    let n = nums.len();
    let mut max_len = 1;
    for i in 0..n {
        let target = nums[i] * k;
        let mut low = i;
        let mut high = n - 1;
        let mut res = i;
        while low <= high {
            let mid = (low + high) / 2;
            if nums[mid] > target {
                res = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        let len = if res == i {
            n - i
        } else {
            res - i
        };
        if len > max_len {
            max_len = len;
        }
    }
    (n as i64) - max_len as i64
}
```

