fn solve(nums: Vec<i64>, k: i64) -> i64 {
    let mut nums = nums;
    nums.sort();
    let n = nums.len();
    let mut max_len = 1;
    for i in 0..n {
        let target = nums[i] * k;
        let mut low = i;
        let mut high = n;
        while low < high {
            let mid = (low + high) / 2;
            if nums[mid] <= target {
                low = mid + 1;
            } else {
                high = mid;
            }
        }
        let j = low - 1;
        let len = j - i + 1;
        if len > max_len {
            max_len = len;
        }
    }
    n as i64 - max_len as i64
}
